import React, { useState, useEffect, useCallback } from 'react';
import { PresentationLayout } from './components/Layout';
import { 
  CoverSlide, 
  SummarySlide, 
  DataSlide, 
  TeamSlide, 
  StrategySlide, 
  ArchitectureSlide, 
  RiskSlide, 
  AllocationSlide, 
  ProcessSlide, 
  ComplianceSlide, 
  MarketSlide, 
  ContactSlide 
} from './components/Slides';

const App: React.FC = () => {
  const [currentSlide, setCurrentSlide] = useState(0);
  const totalSlides = 12;

  const nextSlide = useCallback(() => {
    setCurrentSlide((prev) => (prev + 1) % totalSlides);
  }, []);

  const prevSlide = useCallback(() => {
    setCurrentSlide((prev) => (prev - 1 + totalSlides) % totalSlides);
  }, []);

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'ArrowRight' || e.key === ' ') nextSlide();
      if (e.key === 'ArrowLeft') prevSlide();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [nextSlide, prevSlide]);

  const renderSlide = () => {
    switch (currentSlide) {
      case 0: return <CoverSlide />;
      case 1: return <SummarySlide />;
      case 2: return <DataSlide />;
      case 3: return <TeamSlide />;
      case 4: return <StrategySlide />;
      case 5: return <ArchitectureSlide />;
      case 6: return <RiskSlide />;
      case 7: return <AllocationSlide />;
      case 8: return <ProcessSlide />;
      case 9: return <ComplianceSlide />;
      case 10: return <MarketSlide />;
      case 11: return <ContactSlide />;
      default: return <CoverSlide />;
    }
  };

  return (
    <PresentationLayout 
      currentSlide={currentSlide} 
      totalSlides={totalSlides}
      onNext={nextSlide}
      onPrev={prevSlide}
    >
      {renderSlide()}
    </PresentationLayout>
  );
};

export default App;

