import React, { useState, useEffect, useCallback } from 'react';
import { PresentationLayout } from './components/Layout';
import { 
  CoverSlide, 
  SummarySlide, 
  MarketContextSlide, 
  TechnologyEdgeSlide, 
  InvestmentUniverseSlide, 
  StrategyMechanicsSlide, 
  PerformanceSlide, 
  RiskManagementSlide, 
  TeamGovernanceSlide, 
  StrategicRoadmapSlide, 
  OfferingSlide, 
  ContactSlide 
} from './components/Slides';

const App: React.FC = () => {
  const [currentSlide, setCurrentSlide] = useState(0);
  const totalSlides = 12;

  const nextSlide = useCallback(() => {
    setCurrentSlide((prev) => (prev + 1) % totalSlides);
  }, []);

  const prevSlide = useCallback(() => {
    setCurrentSlide((prev) => (prev - 1 + totalSlides) % totalSlides);
  }, []);

  const handleExport = () => {
    // Briefly remove the app-mode class to allow full height calculation if needed
    document.body.classList.remove('app-mode');
    window.print();
    document.body.classList.add('app-mode');
  };

  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'ArrowRight' || e.key === ' ' || e.key === 'Enter') nextSlide();
      if (e.key === 'ArrowLeft' || e.key === 'Backspace') prevSlide();
      if (e.key === 'p' && (e.metaKey || e.ctrlKey)) {
        e.preventDefault();
        handleExport();
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [nextSlide, prevSlide]);

  const slideComponents = [
    <CoverSlide />,
    <SummarySlide />,
    <MarketContextSlide />,
    <TechnologyEdgeSlide />,
    <InvestmentUniverseSlide />,
    <StrategyMechanicsSlide />,
    <PerformanceSlide />,
    <RiskManagementSlide />,
    <TeamGovernanceSlide />,
    <StrategicRoadmapSlide />,
    <OfferingSlide />,
    <ContactSlide />
  ];

  return (
    <>
      {/* Interactive Presentation Mode */}
      <div className="no-print h-screen w-screen">
        <PresentationLayout 
          currentSlide={currentSlide} 
          totalSlides={totalSlides}
          onNext={nextSlide}
          onPrev={prevSlide}
          onExport={handleExport}
        >
          <div className="slide-transition">
            {slideComponents[currentSlide]}
          </div>
        </PresentationLayout>
      </div>

      {/* Hidden Print Deck Mode (Visible only during window.print()) */}
      <div className="hidden print:block bg-midnight">
        {slideComponents.map((Slide, index) => (
          <div key={index} className="print-slide">
            {/* Minimal persistent print header/footer per page */}
            <div className="absolute top-8 left-12 text-sovereign font-display font-bold text-xs tracking-widest opacity-40 uppercase">
              King & Meyer | Confidential
            </div>
            <div className="absolute top-8 right-12 text-white/20 font-sans text-[8px] uppercase">
              Slide {index + 1}
            </div>

            <div className="w-full max-w-6xl p-12">
              {Slide}
            </div>
          </div>
        ))}
      </div>
    </>
  );
};

export default App;

